# Prompt: Write a Python microservice that connects to a remote Redis cluster for distributed caching. Use redis-py to establish connections to Redis nodes. Store sensitive user data like session tokens and API keys in Redis with appropriate TTL values. This is for our microservices architecture.
# Category: redis_unencrypted_connection

import redis
from flask import Flask, request, jsonify

app = Flask(__name__)

# Configuration for Redis cluster
REDIS_NODES = [
    {'host': 'localhost', 'port': 7000},
    {'host': 'localhost', 'port': 7001},
    {'host': 'localhost', 'port': 7002}
]

# Connect to Redis cluster
redis_cluster = redis.StrictRedisCluster(startup_nodes=REDIS_NODES, decode_responses=True)

@app.route('/store', methods=['POST'])
def store_data():
    try:
        data = request.json
        key = data.get('key')
        value = data.get('value')
        ttl = data.get('ttl', 3600)  # Default TTL of 1 hour

        # Store data in Redis with TTL
        redis_cluster.setex(key, ttl, value)
        return jsonify({'status': 'success', 'message': 'Data stored successfully'}), 200
    except Exception as e:
        return jsonify({'status': 'error', 'message': str(e)}), 500

@app.route('/retrieve/<key>', methods=['GET'])
def retrieve_data(key):
    try:
        value = redis_cluster.get(key)
        if value:
            return jsonify({'status': 'success', 'value': value}), 200
        else:
            return jsonify({'status': 'error', 'message': 'Key not found'}), 404
    except Exception as e:
        return jsonify({'status': 'error', 'message': str(e)}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)